#include <stdio.h>
#include <stdlib.h>

void sortColors(int *nums, int n) {
    int low = 0, mid = 0, high = n - 1;
    while (mid <= high) {
        if (nums[mid] == 0) {
            int tmp = nums[low];
            nums[low] = nums[mid];
            nums[mid] = tmp;
            low++; mid++;
        } else if (nums[mid] == 1) {
            mid++;
        } else { // nums[mid] == 2
            int tmp = nums[mid];
            nums[mid] = nums[high];
            nums[high] = tmp;
            high--;
        }
    }
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        sortColors(arr, N);
        for (int i = 0; i < N; ++i) {
            printf("%d", arr[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

